import numpy as np 
import pandas as pd
def get_categorical_descriptive_df(df, categorical_cols):
    rows = []

    for col in categorical_cols:
        series = df[col].dropna()
        if series.empty:
            continue

        vc = series.value_counts()
        probs = vc / vc.sum()

        entropy = -np.sum(probs * np.log2(probs))

        rows.append({
            : col,
            : series.nunique(),
            : vc.idxmax(),
            : vc.max(),
            : round(entropy, 2)
        })

    return pd.DataFrame(rows)

def get_numerical_descriptive_df(df, numeric_cols):
    rows = {}

    for col in numeric_cols:
        series = df[col].dropna()
        if series.empty:
            continue

        rows[col] = {
            : round(series.mean(), 6),
            : round(series.median(), 6),
            : round(series.std(), 6),
            : round(series.min(), 6),
            : round(series.max(), 6),
            : round(series.skew(), 6),
            : round(series.kurtosis(), 6),
            : round(series.std() / series.mean(), 6) if series.mean() != 0 else np.nan
        }

    return pd.DataFrame.from_dict(rows, orient="index")

